var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"침식체 처리 완료.","JPN":"侵食体の始末完了。","ENG":"C.O.s neutralized.","TWN":"侵蝕體擊殺完畢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"파손된 기계 개체 발견.","JPN":"破損した機械個体を発見。","ENG":"Discovered a damaged mechanical unit.","TWN":"發現破損的機械個體。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_31"},{"id":"L6_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_BROKEN","text":{"KOREA":"다른 로봇?","JPN":"別のロボット？","ENG":"You're a robot, too.","TWN":"其他機器人？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_12"},{"id":"L7_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_BROKEN","text":{"KOREA":"이봐, 난...... 너무 많이 다쳤어. 하반신에 감각이 없다고.","JPN":"ああ、ボクは……大ケガをしている。\\n下半身に感覚がないんだ。","ENG":"Hey... It's too late for me. I can't feel my legs.","TWN":"喂，我……受了重傷，下半身失去知覺了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_BROKEN","text":{"KOREA":"괴물들이 더 몰려오기 전에......","JPN":"バケモノがさらに押し寄せる前に……","ENG":"Before more monsters show up,","TWN":"在更多怪物出現之前……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_BROKEN","text":{"KOREA":"그냥 이대로 두고 가.","JPN":"ボクのことは放っておいて、ここを離れなよ。","ENG":"you'd better leave.","TWN":"快走吧，別管我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_BROKEN","text":{"KOREA":"안녕...... 그 동안 즐거웠다. 잔인한 세상아......","JPN":"さようなら……これまで楽しかった、残酷な世界よ……","ENG":"Goodbye. It's been fun, cruel world...","TWN":"再見……殘酷的世界，我過得很快樂……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"개체 수복을 시작합니다.","JPN":"個体の修復を開始します。","ENG":"Initializing repairs...","TWN":"正在修復個體。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"수복 가능성 99.875%","JPN":"修復可能性99.875％","ENG":"Possibility of recovery: 99.875%.","TWN":"修復成功率99.875%。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L14_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"뭐야. 내 몸이 다시 붙었잖아?","JPN":"そんなバカな！　体が元に戻ってる？","ENG":"What the heck? I'm whole again.","TWN":"啊，我的身體被重新連上了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"네가 치료해준 거야?","JPN":"キミが治療してくれたのか？","ENG":"Did you fix me?","TWN":"是你救我的嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"너 굉장하구나!","JPN":"キミ、すごいんだね！","ENG":"You're amazing!","TWN":"你好厲害！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"수리 완료. 임무 수행을 위해 현장으로 복귀합니다.","JPN":"修理完了。任務遂行のために現場に戻ります。","ENG":"Repair complete. Returning to mission...","TWN":"修理完畢，返回現場執行任務。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L20_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"잠깐 기다려! 난 은혜를 갚을 줄 아는 로봇이라고!","JPN":"ちょっと待って！　ボクは受けた恩はちゃんと\\n返すタイプなんだ！","ENG":"Wait! I want to repay you!","TWN":"等等！我可是有恩必報的機器人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"......이봐! 같이 가!","JPN":"……ねえ！　一緒にいこうよ！","ENG":"Hey! Wait for me!","TWN":"……喂！等等我！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_11"},{"id":"L25_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"솔직히, 네가 나타났을 때 정말 기뻤어.","JPN":"正直、キミが現れた時とても嬉しかったんだ。","ENG":"Honestly, I was happy when you showed up.","TWN":"其實，看到你出現後我非常高興。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L26_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그 동안은 계속 조약돌 하고 얘길 나눠야 했거든.","JPN":"しばらくの間、話し相手といえば石ころだけ\\nだったんだからね。","ENG":"I was tired of only having pebbles to talk to.","TWN":"因為之前我只能和鵝卵石對話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"끔찍한 시간이었지.","JPN":"本当に大変だったんだ。","ENG":"It was terrible.","TWN":"真是不堪回首的經歷。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"주니어가 세상을 뜬 뒤로 제대로 된 말 상대를 만나보는 게 얼마만인지 몰라.","JPN":"ジュニアがあの世に逝ってから、まともな話し相手に\\n会うのは実に久々のことでね。","ENG":"I can't even remember how long it's been since I talked to anyone after Junior's passing.","TWN":"自從尤尼奧爾死後，我好久沒有遇到能說話的對象了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"얼마 전에 내 타이머가 고장이 나버려서 시간감각마저 사라졌거든.","JPN":"ちょっと前にボクのタイマーが壊れちゃって、時間の\\n感覚すらバグってしまったんだ。","ENG":"I couldn't even tell time anymore after my timer broke.","TWN":"而且在不久之前，我的計時器發生了故障，我再也無法計算時間了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"아! 주니어는 로봇강아지야.","JPN":"あ！　ジュニアって犬型ロボットのことさ。","ENG":"Oh, Junior was a robot dog.","TWN":"喔！尤尼奧爾是一隻機器狗。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그 귀여운 친구는 비록 말은 안 통했지만 날 곧잘 따랐어.","JPN":"あの可愛い奴は言葉こそ通じなかったけど、\\nボクに懐いてたんだ。","ENG":"He couldn't talk, but he followed me wherever I went.","TWN":"那可愛的小傢伙雖然不會說話，但很喜歡我。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그 못된 꼬리 다섯 달린 변종이 주니어를 깔아뭉개기 전까진 말이야.","JPN":"あの憎き五尾の変種に押しつぶされるまではね。","ENG":"Until that mean five-tailed mutant crushed him flat.","TWN":"可惜被那長有五條尾巴的變種壓死了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"......이런, 내 소개만 하고 있었네.","JPN":"……あちゃあ、ボクのことばかり喋ってたね。","ENG":"Oops, I've talked too much.","TWN":"……啊，是我太嘮叨了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"이제 네 차례야!","JPN":"今度はキミの番だよ！","ENG":"Now, it's your turn!","TWN":"輪到你來說了！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"아아, 알겠어!","JPN":"ああ、なるほど！","ENG":"Ah, I got it.","TWN":"啊啊，我知道！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"과묵한 타입이라는 거지?","JPN":"寡黙なタイプってことだね？","ENG":"You're the quiet type, huh?","TWN":"你不愛說話對不對？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"난 개성을 존중하는 편이니까, 그 정돈 이해할 수 있어.","JPN":"ボクは個性を尊重するから、それくらいは理解できるよ。","ENG":"I respect individuality. I can understand that.","TWN":"我尊重你的個性，可以理解。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그나저나 어디서 온 거야?","JPN":"それより、どこから来たの？","ENG":"But where did you come from?","TWN":"話說你是從哪裡來的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"너도 같이 다니는 가족이 있니? 친구라던가.","JPN":"キミにも家族や友達がいるのかな？","ENG":"Do you have family? Friends?","TWN":"你有家人或者朋友嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그렇지, 과묵한 타입. 자꾸 깜박깜박한다니까.","JPN":"そうだね、寡黙なタイプだった。うっかりしちゃったよ。","ENG":"Oh, right—you're the quiet type. I keep forgetting.","TWN":"對對，你不愛說話，忘了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L48_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그럼 내 소개부터 할게.","JPN":"じゃあ、ボクの紹介を先にするよ。","ENG":"Then, let me introduce myself first.","TWN":"那我先來自我介紹吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"한때 난 가정집에서 일하던 가사도우미 로봇이었어.","JPN":"一時期、ボクは一般家庭で働く家事手伝いロボットだった。","ENG":"I used to be a housekeeping robot,","TWN":"我本來是一個幫傭機器人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"감수성이 좀 풍부한 편이라서 참견을 많이 했더니 불량품으로 반품됐지.","JPN":"でも、元々感受性が豊かなほうでね、持ち主に\\n色々意見をしたら、不良品扱いされて\\n返品になったんだ。","ENG":"and my owner returned me because I said some things that I shouldn't have. My sensitivity is my undoing.","TWN":"但由於我天生愛嘮叨，被當作殘次品退貨了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그 다음엔 아트홀 센터 청소부를 맡게 됐고......","JPN":"その後は博物館の掃除係になって……","ENG":"After that, I was sent to an art center as a cleaning robot.","TWN":"然後我還在藝術大廳做過清掃工作……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"돌이켜보면 그건 꽤 나쁘지 않은 삶이었어.","JPN":"振り返ってみれば、それはなかなか悪くない人生だった。","ENG":"In retrospect, it wasn't such a bad life.","TWN":"現在回想起來，可以說還不錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"흠......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"아까 보니 꽤 잘 싸우던데, 전투용 로봇이야?","JPN":"さっきはなかなかの腕だったけど、戦闘用ロボットかな？","ENG":"I saw you fight. You're pretty good. Are you a combat robot?","TWN":"我看你剛才很能打，是戰鬥用機器人嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"살면서 너처럼 생긴 디자인은 본 적이 없거든.","JPN":"これまでキミのような形をしてるロボットは\\n見たことがないんだ。","ENG":"I've never seen a robot designed like you before.","TWN":"我從沒見過你這種模樣的機器人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"바퀴도 없이 둥둥 떠다니는데다 번쩍거리는 빛 줄기도 마구 쏴대고 말이야.","JPN":"車輪もないのに空中に浮かんでいるし、光線も\\n乱射してたし。","ENG":"You can glide without wheels, and even shoot shiny laser beams.","TWN":"沒有輪胎，浮在空中，還會發射一些閃亮的光束。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"혹시 인류를 구원하기 위해 시간 저편에서 온 미래로봇 같은 건가?","JPN":"もしかして、人類を救うために時空を越えてやってきた\\n未来のロボットだとか？","ENG":"Are you some sort of high-tech robot that came from the future to save mankind?","TWN":"難道是為了拯救人類而來到這個世界的未來機器人？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그래. 계속해서 나 혼자 떠들어댈 뿐이지.","JPN":"だよねー。答える気なんてないよねー。","ENG":"Yeah, yeah. You want me to shut up, don't you?","TWN":"嗯，只有我一個人在說話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"심심하니 책이나 읽어야겠다.","JPN":"つまんないし本でも読もうっと。","ENG":"I'm just going to read a book, then.","TWN":"好無聊，我要讀一下書。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......오염되지 않은 온전한 문서 발견.","JPN":"……汚染されていない無傷の文書を発見。","ENG":"Uncontaminated, undamaged document discovered.","TWN":"……發現未被污染的完整檔案。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"스캔을 시작합니다.","JPN":"スキャンを開始します。","ENG":"Scanning...","TWN":"開始掃描。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L19_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"아, 정말? 이러기야?","JPN":"マジ？　ひどくない？","ENG":"Oh, come on! Are you serious?","TWN":"啊，你？你幹什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"내가 가장 아끼는 책인데, 그걸 빼앗아간다고?","JPN":"ボクの一番大好きな本なのに、それを取り上げるわけ？","ENG":"That's my favorite book. Are you really going to take it away from me?","TWN":"你竟然搶走我最愛惜的書？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"스캔 완료. 카테고리 분류...... 어린이 그림동화집.","JPN":"スキャン完了。カテゴリー……子ども向けの絵本。","ENG":"Scanning completed. Category: Illustrated children's book.","TWN":"掃描完畢，分類為……兒童童話集。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"문서 중요도...... 매우 낮음.","JPN":"文書の重要度は……最低。","ENG":"Document priority: Very low.","TWN":"文件重要度……極低。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"아, 최악의 감상평까지 완벽하구만 그래.","JPN":"やれやれ、最悪な感想までつけてくれてありがとう。","ENG":"Wow, that's the worst review I've ever heard.","TWN":"啊，這就是你對這本書的評語嗎，真是過分。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"하지만 책이라는 건 말이지, 단순히 스캐닝 한 것 만으로 읽었다고 할 순 없어.","JPN":"けど、本ってスキャンしただけで読んだとは\\n言えないんだよ？","ENG":"But you can't say you've read a book simply by scanning through it.","TWN":"但是，你不能單純靠掃描來判斷書的價值。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"책은 마음의 양식이거든.","JPN":"本は心の栄養なんだ。","ENG":"Books are food for the mind.","TWN":"書是心靈的糧食。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"문장 하나 하나를 이해하고 마음으로 받아들여야 한다고.","JPN":"文章一つ一つを噛みしめて、心に落とし込むんだ。","ENG":"You have to understand and embrace each and every sentence in them.","TWN":"你必須逐字逐句理解，然後用心去領悟。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그렇게 하기 전까진 결코, 함부로 그 책을 읽었다고 단언하면 안돼.","JPN":"それまでは決してその本を読破したとは言えない。","ENG":"Until you do that, you can't say you've read a book.","TWN":"不然，你就沒資格說你讀過書。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"뭐, 우리 차가운 미래로봇 아가씨는 어차피 이 말의 뜻을 모르겠지만 말이야.","JPN":"まあ、無感情な未来のロボットちゃんには\\nどういう意味かわからないだろうけどね。","ENG":"Then again I doubt you, a futuristic ice princess, even know what I'm saying.","TWN":"當然，冰冷的未來機器人小姐是理解不了我說的話的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};